/*
 * sous_vide.ino — Smart Sous-Vide Cooker
 *
 * Elements:
 *   1. MAX31865 PT100 RTD Amplifier  — SPI, water temperature at 5 Hz
 *   2. Solid-State Relay             — GPIO 5, 1-s window PID duty-cycle
 *   3. Rotary Encoder KY-040         — setpoint ±0.1 °C per detent, UI navigation
 *   4. SSD1306 OLED                  — setpoint / actual / timer / PID bar
 *   5. DS3231 RTC                    — cook timer countdown + end alarm
 *   6. Arduino Nano                  — PID loop at 5 Hz
 */

#include <Wire.h>
#include <SPI.h>
#include <Adafruit_MAX31865.h>
#include <Adafruit_SSD1306.h>
#include <RTClib.h>

// --- Pins ---
#define CS_RTD     10
#define SSR_PIN     5
#define ENC_CLK     2   // INT0
#define ENC_DT      4
#define ENC_SW      3
#define BUZZ_PIN    8

// --- Constants ---
#define RNOM       100.0f   // PT100
#define RREF       430.0f   // reference resistor on MAX31865 board
#define KP         10.0f
#define KI          0.5f
#define KD          1.5f
#define PID_PERIOD_MS 200UL   // 5 Hz
#define WINDOW_MS  1000UL     // 1-s SSR duty window

// --- Objects ---
Adafruit_MAX31865 rtd(CS_RTD);
Adafruit_SSD1306  oled(128, 64, &Wire, -1);
RTC_DS3231        rtclock;

// --- State ---
float setpoint    = 60.0f;
float actual_temp = 20.0f;
float pid_integral = 0.0f;
float pid_prev_err = 0.0f;
float pid_output   = 0.0f;

volatile int  enc_delta = 0;
volatile bool enc_press = false;
unsigned long cook_end_epoch = 0;
bool  cooking   = false;
bool  cook_done = false;

void ICACHE_RAM_ATTR on_enc_clk() {
  enc_delta += digitalRead(ENC_DT) ? -1 : 1;
}
void ICACHE_RAM_ATTR on_enc_sw() { enc_press = true; }

float run_pid(float sp, float pv, float dt_s) {
  float err = sp - pv;
  pid_integral  += err * dt_s;
  pid_integral   = constrain(pid_integral, 0.0f, 100.0f / KI);
  float deriv    = (err - pid_prev_err) / dt_s;
  pid_prev_err   = err;
  return constrain(KP * err + KI * pid_integral + KD * deriv, 0.0f, 100.0f);
}

void update_oled() {
  char timer_buf[16];
  if (cooking && !cook_done) {
    long rem = (long)cook_end_epoch - (long)(millis() / 1000);
    if (rem < 0) rem = 0;
    snprintf(timer_buf, sizeof(timer_buf), "%02ld:%02ld", rem / 60, rem % 60);
  } else {
    snprintf(timer_buf, sizeof(timer_buf), cook_done ? "DONE!" : "--:--");
  }
  oled.clearDisplay();
  oled.setTextSize(1); oled.setTextColor(SSD1306_WHITE);
  oled.setCursor(0,  0); oled.printf("Set: %.1f  Act: %.1f", setpoint, actual_temp);
  oled.setCursor(0, 16); oled.printf("Timer: %s", timer_buf);
  oled.setCursor(0, 32);
  oled.printf("PID: %.0f %%", pid_output);
  // Simple bar
  int bar = (int)(pid_output / 100.0f * 100);
  oled.fillRect(0, 44, bar, 8, SSD1306_WHITE);
  oled.display();
}

void setup() {
  Serial.begin(115200);
  Wire.begin();
  SPI.begin();

  rtd.begin(MAX31865_2WIRE);
  oled.begin(SSD1306_SWITCHCAPVCC, 0x3C);
  oled.clearDisplay(); oled.display();
  rtclock.begin();

  pinMode(SSR_PIN, OUTPUT); digitalWrite(SSR_PIN, LOW);
  pinMode(BUZZ_PIN, OUTPUT); digitalWrite(BUZZ_PIN, LOW);
  pinMode(ENC_CLK, INPUT_PULLUP);
  pinMode(ENC_DT,  INPUT_PULLUP);
  pinMode(ENC_SW,  INPUT_PULLUP);
  attachInterrupt(digitalPinToInterrupt(ENC_CLK), on_enc_clk, FALLING);
  attachInterrupt(digitalPinToInterrupt(ENC_SW),  on_enc_sw,  FALLING);

  Serial.println(F("Sous-vide ready."));
}

void loop() {
  static unsigned long last_pid    = 0;
  static unsigned long window_start = 0;

  unsigned long now = millis();

  // --- 1. Encoder: adjust setpoint ---
  noInterrupts();
  int delta = enc_delta; enc_delta = 0;
  bool press = enc_press; enc_press = false;
  interrupts();

  setpoint = constrain(setpoint + delta * 0.1f, 20.0f, 95.0f);

  if (press) {
    // Toggle cook timer (simple: 60-min default for demo)
    if (!cooking) {
      cook_end_epoch = now / 1000 + 3600;
      cooking  = true;
      cook_done = false;
    } else {
      cooking = false;
      digitalWrite(SSR_PIN, LOW);
    }
  }

  // --- Cook timer check ---
  if (cooking && !cook_done && (now / 1000 >= cook_end_epoch)) {
    cook_done = true;
    cooking   = false;
    digitalWrite(SSR_PIN, LOW);
    // Buzzer 5 × beep
    for (int i = 0; i < 5; i++) {
      digitalWrite(BUZZ_PIN, HIGH); delay(200);
      digitalWrite(BUZZ_PIN, LOW);  delay(200);
    }
  }

  // --- 2. PID at 5 Hz ---
  if (now - last_pid >= PID_PERIOD_MS) {
    float dt = (now - last_pid) / 1000.0f;
    last_pid = now;
    actual_temp = rtd.temperature(RNOM, RREF);
    if (cooking) pid_output = run_pid(setpoint, actual_temp, dt);
    else         pid_output = 0.0f;

    Serial.printf("T=%.2f SP=%.1f PID=%.1f\n", actual_temp, setpoint, pid_output);
  }

  // --- 3. SSR window (1 s) ---
  if (cooking) {
    if (now - window_start >= WINDOW_MS) window_start = now;
    bool ssr_on = (now - window_start) < (unsigned long)(pid_output * WINDOW_MS / 100.0f);
    digitalWrite(SSR_PIN, ssr_on ? HIGH : LOW);
  } else {
    digitalWrite(SSR_PIN, LOW);
  }

  // --- 4. OLED ---
  static unsigned long last_oled = 0;
  if (now - last_oled >= 500UL) {
    last_oled = now;
    update_oled();
  }
}
